#!/usr/bin/env python3\nimport json\nfrom pathlib import Path\n\nROOT = Path(__file__).resolve().parents[1]\nARTIFACT = ROOT / "artifacts" / "gravity" / "kerr_desitter_wccc_source_map_2026_05_22.json"\n\ndata = json.loads(ARTIFACT.read_text())\n\nassert data["id"] == "KERR_DESITTER_WCCC_SOURCE_MAP_2026_05_22"\nassert data["status"] == "MODEL_SPECIFIC_WCCC_SOURCE_ONLY_NO_GRAVITY_CLOSURE"\n\nsource = data["source"]\nassert source["title"] == "Kerr-de Sitter black holes: quantum aspects and cosmic censorship conjecture"\nassert source["doi"] == "10.1140/epjc/s10052-026-15720-1"\nassert source["journal"] == "The European Physical Journal C"\nassert source["published"] == "2026-05-17"\nassert source["url"] == "https://link.springer.com/article/10.1140/epjc/s10052-026-15720-1"\n\nassert "MODEL_SPECIFIC_WCCC_HORIZON_ROBUSTNESS_SOURCE" in data["supplies"]\n\ndoes_not_supply = set(data["does_not_supply"])\nfor missing in [\n    "CHRONOS_GRAVITY_STACK_BINDING_MAP",\n    "LARGE_D_TO_D4_ERROR_CONTROL_OR_TRANSFER_THEOREM",\n    "NONSPHERICAL_STABILITY_OR_EXTENSION_THEOREM",\n    "GENERAL_MATTER_TRANSFER_MAP",\n    "SIX_FIELD_ANALYTIC_PACKAGE_HYPOTHESIS",\n]:\n    assert missing in does_not_supply\n\nassert (\n    data["weakest_sufficient_missing_lemma"]\n    == "MODEL_SPECIFIC_QKDS_WCCC_TO_CHRONOS_GRAVITY_STACK_BINDING_MAP"\n)\n\nboundary = "\n".join(data["boundary"])\nfor line in [\n    "Model-specific weak cosmic censorship source only.",\n    "No gravity closure is claimed.",\n    "No unrestricted cosmic censorship theorem is claimed.",\n    "No hoop conjecture result is claimed.",\n    "No four-dimensional non-symmetric collapse theorem is claimed.",\n    "No Chronos gravity stack binding map is claimed.",\n    "No DFM-MKC validation is claimed.",\n    "No dark matter detection is claimed.",\n    "No Clay problem is claimed.",\n]:\n    assert line in boundary\n\ndoes_not_prove = set(data["does_not_prove"])\nfor forbidden in [\n    "gravity closure",\n    "unrestricted cosmic censorship",\n    "hoop conjecture",\n    "four-dimensional non-symmetric collapse theorem",\n    "Chronos gravity stack binding map",\n    "DFM-MKC validation",\n    "dark matter detection",\n    "any Clay problem",\n]:\n    assert forbidden in does_not_prove\n\nprint("Kerr-de Sitter WCCC source-map verification OK.")\nprint(f"Status: {data['status']}")\nprint(f"Weakest sufficient missing lemma: {data['weakest_sufficient_missing_lemma']}")\n